mapper.select:
SELECT
COUNT(*) AS total
FROM
class c
LEFT JOIN `user` u ON u.id = c.user_id

    
        AND c.class_name = #{className}
    
    
        AND c.user_id = #{userId}
    
    
        AND c.create_time = #{createTime}

SELECT
u.user_name AS userName,

FROM
class c
LEFT JOIN `user` u ON u.id = c.user_id
LEFT JOIN `course` co ON co.id = c.course_id

    
        AND c.class_name = #{className}
    
    
        AND c.user_id = #{userId}
    
    
        AND c.create_time = #{createTime}
    

ORDER BY c.id DESC
LIMIT #{page},#{pageSize}

SELECT
u.user_name AS userName,

FROM
class c
LEFT JOIN `user` u ON u.id = c.user_id
LEFT JOIN `course` co ON co.id = c.course_id

    
        AND c.id = #{id}
    
    
        AND c.user_id = #{userId}
    
    
        AND c.course_id = #{courseId}
